// Embedded C fundamentals
#include <stdint.h>  // uint8_t, uint32_t etc.

// Memory-mapped register access
#define GPIOA_BASE    0x40020000UL
#define GPIOA_MODER   (*((volatile uint32_t*)(GPIOA_BASE + 0x00)))
#define GPIOA_ODR     (*((volatile uint32_t*)(GPIOA_BASE + 0x14)))

// Bit manipulation macros
#define SET_BIT(reg, bit)    ((reg) |=  (1UL << (bit)))
#define CLEAR_BIT(reg, bit)  ((reg) &= ~(1UL << (bit)))
#define READ_BIT(reg, bit)   (((reg) >> (bit)) & 1UL)
#define TOGGLE_BIT(reg, bit) ((reg) ^=  (1UL << (bit)))

// Bitfield struct for register mapping
typedef struct {
  volatile uint32_t MODER;   // Mode register
  volatile uint32_t OTYPER;  // Output type
  volatile uint32_t OSPEEDR; // Speed
  volatile uint32_t PUPDR;   // Pull-up/down
  volatile uint32_t IDR;     // Input data
  volatile uint32_t ODR;     // Output data
} GPIO_TypeDef;

#define GPIOA  ((GPIO_TypeDef*)GPIOA_BASE)

// Configure PA5 as output
GPIOA->MODER |= (1 << 10);  // bits [11:10] = 01 (output)
GPIOA->MODER &= ~(1 << 11);
// Toggle PA5
GPIOA->ODR ^= (1 << 5);

// STM32 Bare-Metal LED Blink (no HAL, no libraries)
// LED on PA5 (Nucleo board)

#include <stdint.h>

// RCC and GPIO register addresses
#define RCC_AHB1ENR  (*((volatile uint32_t*)0x40023830))
#define GPIOA_MODER  (*((volatile uint32_t*)0x40020000))
#define GPIOA_ODR    (*((volatile uint32_t*)0x40020014))

void delay(uint32_t count) {
  while (count--) __asm("nop"); // do nothing N times
}

int main(void) {
  // Step 1: Enable GPIOA clock (bit 0 of AHB1ENR)
  RCC_AHB1ENR |= (1 << 0);

  // Step 2: Configure PA5 as output
  // MODER bits [11:10] = 01 (general purpose output)
  GPIOA_MODER |=  (1 << 10); // set bit 10
  GPIOA_MODER &= ~(1 << 11); // clear bit 11

  // Step 3: Blink forever
  while (1) {
    GPIOA_ODR |=  (1 << 5); // LED ON
    delay(1000000);
    GPIOA_ODR &= ~(1 << 5); // LED OFF
    delay(1000000);
  }
  return 0;
}
// Key observations:
// 1. Must enable clock before any GPIO operation
// 2. volatile prevents compiler from removing register access
// 3. Bit manipulation sets individual bits without affecting others
// 4. No OS, no scheduler — this code runs forever

