// UART bare-metal send/receive (STM32-style)
#define USART2_SR   (*((volatile uint32_t*)0x40004400))
#define USART2_DR   (*((volatile uint32_t*)0x40004404))
#define TXE_BIT  7  // TX buffer empty
#define RXNE_BIT 5  // RX not empty

void uart_send_byte(uint8_t data) {
    while (!((USART2_SR >> TXE_BIT) & 1)); // wait TX empty
    USART2_DR = data;
}

uint8_t uart_recv_byte(void) {
    while (!((USART2_SR >> RXNE_BIT) & 1)); // wait RX ready
    return (uint8_t)USART2_DR;
}

void uart_print(const char* str) {
    while (*str) uart_send_byte(*str++);
}

// SPI transfer (send and receive simultaneously)
uint8_t spi_transfer(uint8_t data) {
    while (!SPI_SR_TXE);   // wait TX empty
    SPI_DR = data;          // send
    while (SPI_SR_BSY);    // wait transfer complete
    return SPI_DR;          // return received byte
}

// Ring buffer for UART RX interrupt
#define RING_SIZE 64
uint8_t ring_buf[RING_SIZE];
volatile uint8_t ring_head = 0, ring_tail = 0;

void ring_push(uint8_t b) {
    ring_buf[ring_head] = b;
    ring_head = (ring_head + 1) % RING_SIZE;
}
uint8_t ring_pop(void) {
    uint8_t b = ring_buf[ring_tail];
    ring_tail = (ring_tail + 1) % RING_SIZE;
    return b;
}

// I2C Read from LM75 Temperature Sensor
// Device address: 0x48 (7-bit)
// Temperature register: 0x00
// Returns 16-bit value, MSB first

// Transaction trace:
// [START]
// [0x48<<1 | 0 = 0x90] [ACK]   ← write address
// [0x00]               [ACK]   ← register pointer
// [START] (repeated start)
// [0x48<<1 | 1 = 0x91] [ACK]   ← read address
// [MSB_DATA]           [ACK]   ← high byte (e.g. 0x18)
// [LSB_DATA]           [NACK]  ← low byte (e.g. 0x00)
// [STOP]
//
// Temperature calculation:
// raw = (MSB << 8) | LSB
// Temperature = raw >> 7  (LM75 is 9-bit, MSB=sign)
// For 0x1800 raw: 0x1800 >> 7 = 0x30 = 48 → 24.0°C
//   (each LSB = 0.5°C, so 48 * 0.5 = 24°C)

// HAL-based read
uint8_t buf[2];
uint8_t reg = 0x00;
HAL_I2C_Master_Transmit(&hi2c1, 0x90, &reg, 1, 100);
HAL_I2C_Master_Receive(&hi2c1, 0x91, buf, 2, 100);
int16_t raw = (buf[0] << 8) | buf[1];
float temp = (raw >> 7) * 0.5f;
printf("Temperature: %.1f C\n", temp);

