# Lab 1: Ring Buffer + UART Driver

Implement a ring buffer for UART reception:

```c
#define RING_SIZE 16

typedef struct {
    uint8_t buf[RING_SIZE];
    volatile uint8_t head;
    volatile uint8_t tail;
} RingBuffer;

void     ring_init(RingBuffer* rb);
void     ring_push(RingBuffer* rb, uint8_t byte);  // called from ISR
int      ring_pop(RingBuffer* rb, uint8_t* byte);  // returns 0 if empty
uint8_t  ring_available(RingBuffer* rb); // bytes available
uint8_t  ring_full(RingBuffer* rb);
```

Test:
1. Push 5 bytes: 'H','e','l','l','o'
2. Verify ring_available() == 5
3. Pop all 5 bytes and verify order ('H' first)
4. Verify ring is empty after popping all
5. Fill ring completely (16 bytes) — verify ring_full()==1
6. Attempt push when full — must NOT overwrite data

lab.starterCode:
// Lab 1: Ring Buffer
#include <stdint.h>
#include <stdio.h>
#include <assert.h>
#include <string.h>

#define RING_SIZE 16

typedef struct {
    uint8_t  buf[RING_SIZE];
    volatile uint8_t head;  // write index
    volatile uint8_t tail;  // read index
} RingBuffer;

void ring_init(RingBuffer* rb) {
    rb->head = 0;
    rb->tail = 0;
    memset(rb->buf, 0, RING_SIZE);
}

// Returns 1 if full
uint8_t ring_full(RingBuffer* rb) {
    return ((rb->head + 1) % RING_SIZE) == rb->tail;
}

// Returns 0 if empty
uint8_t ring_available(RingBuffer* rb) {
    return (rb->head - rb->tail + RING_SIZE) % RING_SIZE;
}

// Push byte (from ISR) — drop if full
void ring_push(RingBuffer* rb, uint8_t byte) {
    if (ring_full(rb)) return; // drop if full
    rb->buf[rb->head] = byte;
    rb->head = (rb->head + 1) % RING_SIZE;
}

// Pop byte — returns 1 if successful, 0 if empty
int ring_pop(RingBuffer* rb, uint8_t* byte) {
    if (rb->head == rb->tail) return 0; // empty
    *byte = rb->buf[rb->tail];
    rb->tail = (rb->tail + 1) % RING_SIZE;
    return 1;
}

int main(void) {
    RingBuffer rb;
    ring_init(&rb);

    // Test 1: push 'Hello'
    const char* msg = "Hello";
    for (int i = 0; i < 5; i++) ring_push(&rb, msg[i]);
    assert(ring_available(&rb) == 5);
    printf("Available after push: %d\n", ring_available(&rb));

    // Test 2: pop and verify order
    uint8_t c;
    for (int i = 0; i < 5; i++) {
        assert(ring_pop(&rb, &c) == 1);
        assert(c == msg[i]);
        printf("Popped: %c\n", c);
    }
    assert(ring_available(&rb) == 0);
    printf("Ring empty: PASSED\n");

    // Test 3: fill completely
    for (int i = 0; i < RING_SIZE-1; i++) ring_push(&rb, i);
    assert(ring_full(&rb));
    printf("Ring full: PASSED\n");

    // Test 4: push when full — must not corrupt
    uint8_t count_before = ring_available(&rb);
    ring_push(&rb, 0xFF); // should be dropped
    assert(ring_available(&rb) == count_before);
    printf("Drop when full: PASSED\n");

    printf("All ring buffer tests PASSED\n");
    return 0;
}

