// Interrupt-driven UART receive with flag
#include <stdint.h>

volatile uint8_t  uart_rx_byte = 0;
volatile uint8_t  uart_rx_ready = 0;

// ISR — called by hardware when UART byte received
void USART2_IRQHandler(void) {
    // Read byte (also clears interrupt flag)
    uart_rx_byte  = USART2->DR;
    uart_rx_ready = 1;  // signal main loop
    // Keep ISR short — no processing here!
}

// Main loop
int main(void) {
    // ... setup UART with interrupt enabled ...

    while (1) {
        if (uart_rx_ready) {
            uint8_t byte;
            // Critical section: read shared variable atomically
            __disable_irq();
            byte          = uart_rx_byte;
            uart_rx_ready = 0;
            __enable_irq();

            // Process byte (can take as long as needed)
            process_byte(byte);
        }
        // Do other work here...
    }
}

// Timer interrupt for periodic task
void TIM2_IRQHandler(void) {
    TIM2->SR &= ~(1 << 0);  // MUST clear interrupt flag first!
    // 1ms tick handler
    systick_count++;
}

// Interrupt-driven button debouncer
// EXTI on PA0, Timer2 for 20ms debounce

typedef enum { IDLE, DEBOUNCING, CONFIRMED } btn_state_t;
volatile btn_state_t btn_state = IDLE;
volatile uint8_t     btn_pressed = 0;

// EXTI ISR — fires on button falling edge
void EXTI0_IRQHandler(void) {
    EXTI->PR = (1 << 0); // clear pending bit
    if (btn_state == IDLE) {
        btn_state = DEBOUNCING;
        // Start 20ms timer
        TIM2->CNT = 0;
        TIM2->CR1 |= TIM_CR1_CEN;
    }
}

// Timer ISR — fires after 20ms
void TIM2_IRQHandler(void) {
    TIM2->SR &= ~TIM_SR_UIF; // clear flag
    TIM2->CR1 &= ~TIM_CR1_CEN; // stop timer

    // Check if button still pressed (active low)
    if (!(GPIOA->IDR & (1 << 0))) {
        btn_state  = CONFIRMED;
        btn_pressed = 1; // signal main loop
    } else {
        btn_state = IDLE; // false press (bounce)
    }
}

// Main loop
while (1) {
    if (btn_pressed) {
        __disable_irq();
        btn_pressed = 0;
        btn_state   = IDLE;
        __enable_irq();
        // Handle button press
        toggle_led();
    }
}

