# Lab 2: Interrupt-Safe Event Queue

Simulate an interrupt-driven system with an event queue:

```c
// Event types
typedef enum { EVT_NONE, EVT_BTN, EVT_UART, EVT_TIMER } event_t;

typedef struct {
    event_t events[8];
    volatile uint8_t head, tail;
} EventQueue;

void   eq_push(EventQueue* eq, event_t evt);  // called from 'ISR'
event_t eq_pop(EventQueue* eq);               // called from main
uint8_t eq_empty(EventQueue* eq);
```

Simulate a system that receives:
1. 2 button events (EVT_BTN)
2. 3 UART events (EVT_UART)  
3. 1 timer event (EVT_TIMER)

Process all events in main loop and verify:
- Total events processed = 6
- Events processed in order
- BTN count = 2, UART count = 3, TIMER count = 1
- Queue empty at end

lab.starterCode:
// Lab 2: Interrupt-Safe Event Queue
#include <stdint.h>
#include <stdio.h>
#include <assert.h>

typedef enum {
    EVT_NONE  = 0,
    EVT_BTN   = 1,
    EVT_UART  = 2,
    EVT_TIMER = 3
} event_t;

#define QUEUE_SIZE 8

typedef struct {
    event_t          events[QUEUE_SIZE];
    volatile uint8_t head;  // write (ISR)
    volatile uint8_t tail;  // read (main)
} EventQueue;

void eq_init(EventQueue* eq) {
    eq->head = 0;
    eq->tail = 0;
}

uint8_t eq_empty(EventQueue* eq) {
    return eq->head == eq->tail;
}

uint8_t eq_full(EventQueue* eq) {
    return ((eq->head + 1) % QUEUE_SIZE) == eq->tail;
}

// Called from ISR (simulated here)
void eq_push(EventQueue* eq, event_t evt) {
    if (eq_full(eq)) return;
    eq->events[eq->head] = evt;
    eq->head = (eq->head + 1) % QUEUE_SIZE;
}

// Called from main loop
event_t eq_pop(EventQueue* eq) {
    if (eq_empty(eq)) return EVT_NONE;
    event_t evt = eq->events[eq->tail];
    eq->tail = (eq->tail + 1) % QUEUE_SIZE;
    return evt;
}

// Simulate critical section
#define ENTER_CRITICAL()  // disable_irq()
#define EXIT_CRITICAL()   // enable_irq()

int main(void) {
    EventQueue eq;
    eq_init(&eq);

    // Simulate ISR pushing events
    eq_push(&eq, EVT_BTN);
    eq_push(&eq, EVT_UART);
    eq_push(&eq, EVT_BTN);
    eq_push(&eq, EVT_UART);
    eq_push(&eq, EVT_TIMER);
    eq_push(&eq, EVT_UART);

    // Main loop processes events
    int total = 0, btn_cnt = 0, uart_cnt = 0, timer_cnt = 0;

    while (!eq_empty(&eq)) {
        event_t evt;
        ENTER_CRITICAL();
        evt = eq_pop(&eq);
        EXIT_CRITICAL();

        switch (evt) {
            case EVT_BTN:   btn_cnt++;   break;
            case EVT_UART:  uart_cnt++;  break;
            case EVT_TIMER: timer_cnt++; break;
            default: break;
        }
        total++;
        printf("Processed event: %d\n", evt);
    }

    assert(total == 6);
    assert(btn_cnt == 2);
    assert(uart_cnt == 3);
    assert(timer_cnt == 1);
    assert(eq_empty(&eq));

    printf("Total: %d events (BTN=%d UART=%d TIMER=%d)\n",
           total, btn_cnt, uart_cnt, timer_cnt);
    printf("Event queue tests PASSED\n");
    return 0;
}

