// FreeRTOS task and queue example
#include "FreeRTOS.h"
#include "task.h"
#include "queue.h"

QueueHandle_t xDataQueue;

// Producer task — reads sensor, sends to queue
void vSensorTask(void* pvParams) {
    uint32_t sensor_data;
    for (;;) {
        sensor_data = read_adc();     // read sensor
        // Send to queue (block up to 10ms if full)
        xQueueSend(xDataQueue, &sensor_data,
                   pdMS_TO_TICKS(10));
        vTaskDelay(pdMS_TO_TICKS(100)); // 100ms period
    }
}

// Consumer task — receives from queue, processes
void vProcessTask(void* pvParams) {
    uint32_t data;
    for (;;) {
        // Block forever until data available
        if (xQueueReceive(xDataQueue, &data,
                          portMAX_DELAY) == pdTRUE) {
            process_data(data);
        }
    }
}

int main(void) {
    // Create queue: 10 items, each uint32_t
    xDataQueue = xQueueCreate(10, sizeof(uint32_t));

    // Create tasks
    xTaskCreate(vSensorTask,  "Sensor",  256, NULL, 2, NULL);
    xTaskCreate(vProcessTask, "Process", 512, NULL, 1, NULL);

    vTaskStartScheduler(); // start RTOS, never returns
    return 0;
}

// FreeRTOS scheduler trace (3 tasks)
// Task A: priority 3 (highest), reads sensor every 10ms
// Task B: priority 2, processes data
// Task C: priority 1 (lowest), sends UART
// Idle: priority 0

// Time 0ms:
//   Scheduler starts → Task A runs (highest priority)
// Time 1ms:
//   Task A calls vTaskDelay(10ms) → BLOCKED
//   Scheduler picks Task B (next highest ready)
// Time 2ms:
//   Task B waits on queue (empty) → BLOCKED
//   Scheduler picks Task C
// Time 5ms:
//   Task C finishes UART send → BLOCKED (vTaskDelay)
//   Scheduler picks Idle task → CPU can enter sleep
// Time 10ms:
//   Task A delay expires → READY
//   Scheduler preempts Idle → Task A RUNNING
//   Task A sends data to queue → Task B becomes READY
//   Task B priority > Task C → preempts when Task A blocks
// Time 11ms:
//   Task A calls vTaskDelay → Task B RUNNING (queue data)

// Key insight: Higher priority tasks preempt lower ones
// Tasks block voluntarily → others get CPU time
// No busy-waiting → efficient CPU usage

