# Lab 3: FreeRTOS-Style Producer-Consumer

Simulate a FreeRTOS producer-consumer without the actual RTOS (pure C):

```c
// Thread-safe queue (simulates FreeRTOS queue)
typedef struct {
    int data[10];
    int head, tail, count;
} RTOSQueue;

void   queue_send(RTOSQueue* q, int val);
int    queue_receive(RTOSQueue* q, int* val); // 1=success
int    queue_count(RTOSQueue* q);
```

Simulate the following scenario:
1. Producer sends 5 sensor values: 10, 20, 30, 40, 50
2. Consumer receives and processes each value (multiply by 2)
3. Store results in array: 20, 40, 60, 80, 100
4. Verify all 5 results are correct
5. Simulate queue full condition (capacity=3): producer blocks (drops)
6. Test: producer sends 5 items to capacity-3 queue → only 3 stored

lab.starterCode:
// Lab 3: FreeRTOS-Style Queue Simulation
#include <stdio.h>
#include <assert.h>

#define QUEUE_MAX 10

typedef struct {
    int data[QUEUE_MAX];
    int head, tail, count, capacity;
} RTOSQueue;

void queue_init(RTOSQueue* q, int cap) {
    q->head = q->tail = q->count = 0;
    q->capacity = cap;
}

int queue_full(RTOSQueue* q)  { return q->count >= q->capacity; }
int queue_empty(RTOSQueue* q) { return q->count == 0; }
int queue_count(RTOSQueue* q) { return q->count; }

// Send to queue (returns 1=ok, 0=full)
int queue_send(RTOSQueue* q, int val) {
    if (queue_full(q)) return 0;
    q->data[q->head] = val;
    q->head = (q->head + 1) % QUEUE_MAX;
    q->count++;
    return 1;
}

// Receive from queue (returns 1=ok, 0=empty)
int queue_receive(RTOSQueue* q, int* val) {
    if (queue_empty(q)) return 0;
    *val = q->data[q->tail];
    q->tail = (q->tail + 1) % QUEUE_MAX;
    q->count--;
    return 1;
}

// Simulate producer task
void producer_task(RTOSQueue* q, int* sensor_data, int n) {
    for (int i = 0; i < n; i++) {
        if (!queue_send(q, sensor_data[i]))
            printf("Queue full! Dropped: %d\n", sensor_data[i]);
        else
            printf("Sent: %d\n", sensor_data[i]);
    }
}

// Simulate consumer task
int consumer_task(RTOSQueue* q, int* results, int max) {
    int count = 0, val;
    while (count < max && queue_receive(q, &val)) {
        results[count++] = val * 2; // process: multiply by 2
    }
    return count;
}

int main(void) {
    RTOSQueue q;
    int sensor_data[] = {10, 20, 30, 40, 50};
    int results[10] = {0};
    int expected[]  = {20, 40, 60, 80, 100};

    // Test 1: capacity 10 (all fit)
    queue_init(&q, 10);
    producer_task(&q, sensor_data, 5);
    int count = consumer_task(&q, results, 10);

    assert(count == 5);
    for (int i = 0; i < 5; i++)
        assert(results[i] == expected[i]);
    printf("Test1 PASSED: %d results correct\n", count);

    // Test 2: capacity 3 (queue overflow)
    queue_init(&q, 3);
    producer_task(&q, sensor_data, 5); // sends 5, only 3 fit
    assert(queue_count(&q) == 3);
    printf("Test2 PASSED: queue held %d/3 items\n", queue_count(&q));

    printf("All RTOS queue tests PASSED\n");
    return 0;
}

