// PWM setup for motor control (STM32 HAL)
// Timer2, Channel1, 1kHz PWM, 25% duty cycle
// System clock: 72MHz

// Period = (PSC+1)*(ARR+1)/fCLK
// Want 1kHz: (71+1)*(999+1)/72MHz = 72000/72MHz = 1ms ✓
htim2.Instance          = TIM2;
htim2.Init.Prescaler    = 71;    // 72MHz/72 = 1MHz timer clock
htim2.Init.Period       = 999;   // 1MHz/1000 = 1kHz
htim2.Init.CounterMode  = TIM_COUNTERMODE_UP;
HAL_TIM_PWM_Init(&htim2);

// Set 25% duty cycle
sConfig.OCMode     = TIM_OCMODE_PWM1;
sConfig.Pulse      = 250;  // 250/1000 = 25%
HAL_TIM_PWM_ConfigChannel(&htim2, &sConfig, TIM_CHANNEL_1);
HAL_TIM_PWM_Start(&htim2, TIM_CHANNEL_1);

// Change duty cycle at runtime
__HAL_TIM_SET_COMPARE(&htim2, TIM_CHANNEL_1, 750); // 75%

// ADC read (blocking, single conversion)
uint32_t adc_read(void) {
    HAL_ADC_Start(&hadc1);
    HAL_ADC_PollForConversion(&hadc1, 10); // 10ms timeout
    uint32_t raw = HAL_ADC_GetValue(&hadc1);
    HAL_ADC_Stop(&hadc1);
    return raw; // 0-4095
}

// Convert to voltage
float adc_voltage(uint32_t raw) {
    return (raw / 4095.0f) * 3.3f; // assuming 3.3V reference
}

// PWM Calculation Examples
// System clock: 72MHz
// Timer2 registers

// EXAMPLE 1: 1kHz PWM, 50% duty
// PSC = 71 → Timer clock = 72MHz/(71+1) = 1MHz
// ARR = 999 → Period = 1MHz/(999+1) = 1kHz ✓
// CCR = 500 → Duty = 500/1000 = 50% ✓

// EXAMPLE 2: 20kHz PWM (servo control)
// Want 20kHz → period = 50μs
// Timer clock at 1MHz → ARR = 1MHz/20kHz - 1 = 49
// PSC = 71, ARR = 49, CCR = 25 → 25/50 = 50%

// EXAMPLE 3: Servo control (50Hz, 1-2ms pulse)
// Servo period = 20ms (50Hz)
// PSC = 71, ARR = 19999 (20ms at 1MHz)
// Min: CCR = 1000 (1ms = 0°)
// Max: CCR = 2000 (2ms = 180°)
// Center: CCR = 1500 (1.5ms = 90°)

// ADC Calculation:
// 12-bit ADC, VREF = 3.3V
// Raw reading = 2048
