    uint32_t samples[8];
    uint8_t  index;
    uint8_t  count;
} ADCFilter;

void    adc_filter_add(ADCFilter* f, uint32_t sample);
uint32_t adc_filter_average(const ADCFilter* f);
float   adc_to_voltage(uint32_t raw, float vref);
```

Test:
1. Set PWM ARR=999, set 25%, 50%, 75% duty — verify CCR values
2. Add 8 ADC samples: 1000,1010,990,1005,995,1008,998,1004
3. Verify average ≈ 1001
4. Map ADC 0-4095 to PWM 0-100% — test with ADC=2048 → 50%

lab.starterCode:
// Lab 4: PWM + ADC Controller
#include <stdint.h>
#include <stdio.h>
#include <assert.h>
#include <math.h>

// PWM structure
typedef struct {
    uint32_t arr;  // period register
    uint32_t ccr;  // compare register (duty)
} PWM;

void pwm_set_duty_percent(PWM* pwm, float duty_pct) {
    if (duty_pct < 0.0f)   duty_pct = 0.0f;
    if (duty_pct > 100.0f) duty_pct = 100.0f;
    pwm->ccr = (uint32_t)((duty_pct / 100.0f) * (pwm->arr + 1));
}

float pwm_get_duty_percent(const PWM* pwm) {
    return ((float)pwm->ccr / (float)(pwm->arr + 1)) * 100.0f;
}

// ADC averaging filter
#define ADC_FILTER_SIZE 8

typedef struct {
    uint32_t samples[ADC_FILTER_SIZE];
    uint8_t  index;
    uint8_t  count;
} ADCFilter;

void adc_filter_init(ADCFilter* f) {
    f->index = 0;
    f->count = 0;
    for (int i=0; i<ADC_FILTER_SIZE; i++) f->samples[i]=0;
}

void adc_filter_add(ADCFilter* f, uint32_t sample) {
    f->samples[f->index] = sample;
    f->index = (f->index + 1) % ADC_FILTER_SIZE;
    if (f->count < ADC_FILTER_SIZE) f->count++;
}

uint32_t adc_filter_average(const ADCFilter* f) {
    if (f->count == 0) return 0;
    uint32_t sum = 0;
    for (int i=0; i<f->count; i++) sum += f->samples[i];
    return sum / f->count;
}

float adc_to_voltage(uint32_t raw, float vref) {
    return ((float)raw / 4095.0f) * vref;
}

int main(void) {
    // Test PWM
    PWM pwm = {.arr = 999, .ccr = 0};

    pwm_set_duty_percent(&pwm, 25.0f);
    assert(pwm.ccr == 250);
    printf("25%% duty: CCR=%u PASSED\n", pwm.ccr);

    pwm_set_duty_percent(&pwm, 50.0f);
    assert(pwm.ccr == 500);
    printf("50%% duty: CCR=%u PASSED\n", pwm.ccr);

    pwm_set_duty_percent(&pwm, 75.0f);
    assert(pwm.ccr == 750);
    printf("75%% duty: CCR=%u PASSED\n", pwm.ccr);

    // Test ADC filter
    ADCFilter f;
    adc_filter_init(&f);
    uint32_t samples[] = {1000,1010,990,1005,995,1008,998,1004};
    for (int i=0; i<8; i++) adc_filter_add(&f, samples[i]);

    uint32_t avg = adc_filter_average(&f);
    printf("ADC average: %u\n", avg);
    assert(avg >= 999 && avg <= 1003); // ≈1001
    printf("ADC filter PASSED\n");

    // Test ADC to PWM mapping
    // ADC=2048 → 50% duty
    uint32_t adc_raw = 2048;
    float duty = (adc_raw / 4095.0f) * 100.0f;
    pwm_set_duty_percent(&pwm, duty);
    printf("ADC=%u → duty=%.1f%% CCR=%u\n", adc_raw, duty, pwm.ccr);
    assert(pwm.ccr >= 499 && pwm.ccr <= 501);

    printf("All PWM+ADC tests PASSED\n");
    return 0;
}

