// Memory pool — fixed-size block allocator
#define POOL_BLOCK_SIZE 32
#define POOL_BLOCK_COUNT 16

typedef struct {
    uint8_t  blocks[POOL_BLOCK_COUNT][POOL_BLOCK_SIZE];
    uint16_t free_mask; // bit=1 means block is free
} MemPool;

void* pool_alloc(MemPool* p) {
    for (int i = 0; i < POOL_BLOCK_COUNT; i++) {
        if (p->free_mask & (1 << i)) {
            p->free_mask &= ~(1 << i); // mark used
            return p->blocks[i];
        }
    }
    return NULL; // pool exhausted
}

void pool_free(MemPool* p, void* ptr) {
    for (int i = 0; i < POOL_BLOCK_COUNT; i++) {
        if (ptr == p->blocks[i]) {
            p->free_mask |= (1 << i); // mark free
            return;
        }
    }
}

