// Lab 5: Memory Pool
#include <stdint.h>
#include <stdio.h>
#include <assert.h>
#include <string.h>

#define POOL_SIZE   8
#define BLOCK_SIZE  16

typedef struct {
    uint8_t blocks[POOL_SIZE][BLOCK_SIZE];
    uint8_t used[POOL_SIZE];
    uint8_t alloc_count;
    uint8_t free_count;
} MemPool;

void pool_init(MemPool* p) {
    memset(p, 0, sizeof(*p));
}

// Returns pointer to free block or NULL
void* pool_alloc(MemPool* p) {
    for (int i = 0; i < POOL_SIZE; i++) {
        if (!p->used[i]) {
            p->used[i] = 1;
            p->alloc_count++;
            return p->blocks[i];
        }
    }
    return NULL;
}

// Free a previously allocated block
void pool_free(MemPool* p, void* ptr) {
    for (int i = 0; i < POOL_SIZE; i++) {
        if (ptr == p->blocks[i] && p->used[i]) {
            p->used[i] = 0;
            p->free_count++;
            return;
        }
    }
}

uint8_t pool_used_count(const MemPool* p) {
    uint8_t count = 0;
    for (int i=0; i<POOL_SIZE; i++) if (p->used[i]) count++;
    return count;
}

uint8_t pool_avail_count(const MemPool* p) {
    return POOL_SIZE - pool_used_count(p);
}

int main(void) {
    MemPool pool;
    pool_init(&pool);

    // Test 1: allocate 4 blocks
    void* ptrs[POOL_SIZE];
    for (int i=0; i<4; i++) {
        ptrs[i] = pool_alloc(&pool);
        assert(ptrs[i] != NULL);
        // Write to verify usable
        ((uint8_t*)ptrs[i])[0] = i;
    }
    assert(pool_used_count(&pool) == 4);
    printf("Test1: 4 allocs, used=%d PASSED\n",pool_used_count(&pool));

    // Test 2: free blocks 1 and 3
    pool_free(&pool, ptrs[1]);
    pool_free(&pool, ptrs[3]);
    assert(pool_used_count(&pool) == 2);
    printf("Test2: 2 frees, used=%d PASSED\n",pool_used_count(&pool));

    // Test 3: allocate fills freed slots
    void* p5 = pool_alloc(&pool);
    void* p6 = pool_alloc(&pool);
    assert(p5 != NULL && p6 != NULL);
    assert(pool_used_count(&pool) == 4);
    printf("Test3: realloc freed slots PASSED\n");

    // Test 4: fill pool completely
    pool_init(&pool);
    for (int i=0; i<POOL_SIZE; i++) {
        ptrs[i] = pool_alloc(&pool);
        assert(ptrs[i] != NULL);
    }
    assert(pool_used_count(&pool) == POOL_SIZE);

    // Test 5: exhausted pool
    void* extra = pool_alloc(&pool);
    assert(extra == NULL);
    printf("Test5: exhausted returns NULL PASSED\n");

    printf("alloc_count=%d free_count=%d\n",
           pool.alloc_count, pool.free_count);
    printf("All memory pool tests PASSED\n");
    return 0;
}

