// Lab 6: Simulated Linux Character Device
#include <stdio.h>
#include <stdint.h>
#include <string.h>
#include <assert.h>

typedef struct {
    uint8_t  led_state[8];
    uint32_t write_count;
    uint32_t read_count;
} LEDDevice;

void dev_init(LEDDevice* dev) {
    memset(dev, 0, sizeof(*dev));
}

int dev_open(LEDDevice* dev) {
    printf("[driver] /dev/led opened\n");
    return 0;
}

// Parse "L5=1" or "L5=0" and set LED
int dev_write(LEDDevice* dev, const char* buf, size_t len) {
    int led_num;
    int led_val;
    if (sscanf(buf, "L%d=%d", &led_num, &led_val) == 2) {
        if (led_num >= 0 && led_num < 8) {
            dev->led_state[led_num] = led_val ? 1 : 0;
            dev->write_count++;
            printf("[driver] LED%d = %d\n", led_num, led_val);
            return len;
        }
    }
    return -1; // EINVAL
}

// Return state string "L0=0,L1=1,..."
int dev_read(LEDDevice* dev, char* buf, size_t maxlen) {
    int offset = 0;
    for (int i = 0; i < 8 && offset < (int)maxlen - 8; i++) {
        if (i > 0) buf[offset++] = ',';
        offset += sprintf(buf + offset, "L%d=%d", i, dev->led_state[i]);
    }
    buf[offset] = '\0';
    dev->read_count++;
    return offset;
}

// ioctl: cmd=1 all ON, cmd=0 all OFF
int dev_ioctl(LEDDevice* dev, int cmd, unsigned long arg) {
    (void)arg;
    uint8_t val = (cmd == 1) ? 1 : 0;
    for (int i = 0; i < 8; i++) dev->led_state[i] = val;
    printf("[driver] ioctl: all LEDs %s\n", val ? "ON" : "OFF");
    return 0;
}

void dev_close(LEDDevice* dev) {
    printf("[driver] /dev/led closed (writes=%u reads=%u)\n",
           dev->write_count, dev->read_count);
}

int main(void) {
    LEDDevice dev;
    dev_init(&dev);
    dev_open(&dev);

    // Test writes
    dev_write(&dev, "L0=1", 4);
    dev_write(&dev, "L3=1", 4);
    dev_write(&dev, "L7=1", 4);
    assert(dev.led_state[0] == 1);
    assert(dev.led_state[3] == 1);
    assert(dev.led_state[7] == 1);
    assert(dev.led_state[1] == 0);
    printf("Write test PASSED\n");

    // Test read
    char buf[128];
    dev_read(&dev, buf, sizeof(buf));
    printf("State: %s\n", buf);
    assert(strstr(buf, "L0=1") != NULL);
    assert(strstr(buf, "L3=1") != NULL);
    printf("Read test PASSED\n");

    // Test ioctl: all OFF
    dev_ioctl(&dev, 0, 0);
    for (int i=0; i<8; i++) assert(dev.led_state[i] == 0);
    printf("ioctl OFF test PASSED\n");

    // Test ioctl: all ON
    dev_ioctl(&dev, 1, 0);
    for (int i=0; i<8; i++) assert(dev.led_state[i] == 1);
    printf("ioctl ON test PASSED\n");

    dev_close(&dev);
    printf("All driver tests PASSED\n");
