// ARM Cortex-M Vector Table
typedef void (*irq_handler_t)(void);

// Placed at 0x08000000 (Flash start) by linker script
__attribute__((section(".isr_vector")))
const irq_handler_t vector_table[] = {
    (irq_handler_t)&_estack,     // [0] initial stack pointer
    Reset_Handler,                // [1] reset
    NMI_Handler,                  // [2] NMI
    HardFault_Handler,            // [3] hard fault
    // ... more handlers
};

// Reset handler — first code to run
void Reset_Handler(void) {
    // Copy .data from Flash to SRAM
    extern uint32_t _sdata, _edata, _sidata;
    uint32_t *src = &_sidata;
    for (uint32_t *dst = &_sdata; dst < &_edata;)
        *dst++ = *src++;

    // Zero .bss
    extern uint32_t _sbss, _ebss;
    for (uint32_t *p = &_sbss; p < &_ebss;)
        *p++ = 0;

    main(); // jump to application
}

// Bootloader jump to application
void bootloader_jump_to_app(uint32_t app_addr) {
    uint32_t* app_vector = (uint32_t*)app_addr;
    uint32_t  app_sp     = app_vector[0]; // stack pointer
    uint32_t  app_reset  = app_vector[1]; // reset handler

    // Relocate vector table
    SCB->VTOR = app_addr;

    // Set stack pointer and jump
    __set_MSP(app_sp);
    ((void(*)(void))app_reset)(); // never returns
}

// Complete ARM Cortex-M Boot Sequence

// 1. HARDWARE RESET
//    CPU reads:
//    - Stack pointer: Flash[0x08000000] = 0x20005000 (top of SRAM)
//    - Reset handler: Flash[0x08000004] = 0x08000141 (Reset_Handler addr)

// 2. RESET_HANDLER executes:
void Reset_Handler(void) {
    // a. Copy initialized data Flash → SRAM
    //    .data section: global int x = 5; → copies value 5
    memcpy(&_sdata, &_sidata, (&_edata - &_sdata) * 4);

    // b. Zero BSS (uninitialized globals)
    memset(&_sbss, 0, (&_ebss - &_sbss) * 4);

    // c. Initialize system clocks
    SystemInit(); // setup PLL: 8MHz crystal → 72MHz CPU

    // d. Call global constructors (C++)
    __libc_init_array();

    // e. Jump to application
    main();

    // f. Should never reach here
    while (1);
}

// 3. MAIN() starts:
//    RCC enables → GPIO init → UART init → ... → superloop

// BOOTLOADER scenario:
int main(void) {
    // Check magic word in backup register
    if (RTC->BKP0R == 0xDEADBEEF) {
        RTC->BKP0R = 0; // clear flag
        dfu_mode();      // enter update mode
    } else {
        bootloader_jump_to_app(0x08010000); // app at 64KB offset
    }
}

