// Lab 7: Firmware CRC Verifier
#include <stdint.h>
#include <stdio.h>
#include <string.h>
#include <assert.h>

#define FW_MAGIC 0xDEADC0DEUL

typedef struct __attribute__((packed)) {
    uint32_t magic;
    uint32_t version;
    uint32_t size;
    uint32_t crc32;
    uint8_t  name[16];
} FirmwareHeader;

// Standard CRC32 (Ethernet polynomial 0xEDB88320)
uint32_t crc32_compute(const uint8_t* data, uint32_t len) {
    uint32_t crc = 0xFFFFFFFF;
    for (uint32_t i = 0; i < len; i++) {
        crc ^= data[i];
        for (int j = 0; j < 8; j++) {
            if (crc & 1)
                crc = (crc >> 1) ^ 0xEDB88320;
            else
                crc >>= 1;
        }
    }
    return ~crc;
}

// Verify firmware: check magic + CRC
// fw_data points to FirmwareHeader followed by firmware bytes
// Returns 1 if valid, 0 if invalid
int fw_verify(const uint8_t* fw_data, uint32_t total_size) {
    const FirmwareHeader* hdr = (const FirmwareHeader*)fw_data;

    // Check magic
    if (hdr->magic != FW_MAGIC) {
        printf("[boot] Invalid magic: 0x%08X\n", hdr->magic);
        return 0;
    }

    // Check size is reasonable
    uint32_t hdr_size = sizeof(FirmwareHeader);
    if (hdr->size + hdr_size > total_size) {
        printf("[boot] Size mismatch\n");
        return 0;
    }

    // Compute CRC over firmware data (after header)
    const uint8_t* fw_code = fw_data + hdr_size;
    uint32_t computed_crc = crc32_compute(fw_code, hdr->size);

    if (computed_crc != hdr->crc32) {
        printf("[boot] CRC FAIL: got 0x%08X exp 0x%08X\n",
               computed_crc, hdr->crc32);
        return 0;
    }

    printf("[boot] FW OK: '%s' v%u size=%u CRC=0x%08X\n",
           hdr->name, hdr->version, hdr->size, hdr->crc32);
    return 1;
}

int main(void) {
    // Build test firmware: header + 256 bytes data
    #define FW_DATA_SIZE 256
    uint8_t firmware[sizeof(FirmwareHeader) + FW_DATA_SIZE];
    memset(firmware, 0, sizeof(firmware));

    // Fill data section with test pattern
    uint8_t* fw_code = firmware + sizeof(FirmwareHeader);
    for (int i=0; i<FW_DATA_SIZE; i++) fw_code[i] = i & 0xFF;

    // Build header
    FirmwareHeader* hdr = (FirmwareHeader*)firmware;
    hdr->magic   = FW_MAGIC;
    hdr->version = 1;
    hdr->size    = FW_DATA_SIZE;
    strncpy((char*)hdr->name, "TestFirmware", 16);
    hdr->crc32   = crc32_compute(fw_code, FW_DATA_SIZE);

    printf("CRC32 = 0x%08X\n", hdr->crc32);

    // Test 1: valid firmware
    assert(fw_verify(firmware, sizeof(firmware)) == 1);
    printf("Test1 PASSED: valid firmware\n");

    // Test 2: corrupt one data byte
    fw_code[128] ^= 0xFF;
    assert(fw_verify(firmware, sizeof(firmware)) == 0);
    fw_code[128] ^= 0xFF; // restore
    printf("Test2 PASSED: corruption detected\n");

    // Test 3: wrong magic
    hdr->magic = 0x12345678;
    assert(fw_verify(firmware, sizeof(firmware)) == 0);
    hdr->magic = FW_MAGIC; // restore
    printf("Test3 PASSED: wrong magic detected\n");

    printf("All bootloader verifier tests PASSED\n");
    return 0;
}

