#include "stm32f4xx_hal.h"

void configure_rtc_wakeup_10s(void) {
    // RTC wakeup timer: 10 second interval
    HAL_RTCEx_SetWakeUpTimer_IT(&hrtc, 10,
                                 RTC_WAKEUPCLOCK_CK_SPRE_16BITS);
