void low_power_task(void) {
    // 1. Disable unused peripheral clocks
    __HAL_RCC_USART2_CLK_DISABLE();  // disable debug UART
    __HAL_RCC_SPI1_CLK_DISABLE();    // disable SPI

    // 2. Configure GPIO to analog input (lowest leakage)
    GPIO_InitTypeDef GPIO_Init = {0};
    GPIO_Init.Mode = GPIO_MODE_ANALOG;
    GPIO_Init.Pull = GPIO_NOPULL;
    GPIO_Init.Pin  = GPIO_PIN_All & ~(SENSOR_PIN | LED_PIN);
    HAL_GPIO_Init(GPIOA, &GPIO_Init);

    // 3. Enter Stop mode (2μA typical)
    // Wake on RTC alarm or external interrupt
    HAL_PWR_EnterSTOPMode(PWR_LOWPOWERREGULATOR_ON,
                           PWR_STOPENTRY_WFI);
    // ... CPU resumes here after wakeup ...

    // 4. Re-initialize clocks after Stop mode
    SystemClock_Config(); // PLL stops in Stop mode

    // 5. Quickly read sensor, transmit, sleep again
    uint32_t data = read_sensor();
    transmit_ble(data);   // fast BLE advertisement
    configure_rtc_wakeup_10s();
    // loop back to Step 1
}

