// Lab 8: Battery Life Calculator
#include <stdio.h>
#include <assert.h>
#include <math.h>

typedef struct {
    float active_current_mA;
    float sleep_current_uA;
    float active_time_ms;
    float cycle_period_ms;
} PowerProfile;

// Average current in microamps
float calc_average_current_uA(const PowerProfile* p) {
    float active_ratio = p->active_time_ms / p->cycle_period_ms;
    float sleep_ratio  = 1.0f - active_ratio;
    float i_active_uA  = p->active_current_mA * 1000.0f;
    return active_ratio * i_active_uA + sleep_ratio * p->sleep_current_uA;
}

// Battery life in hours
float calc_battery_life_hours(const PowerProfile* p, float battery_mAh) {
    float avg_uA = calc_average_current_uA(p);
    float avg_mA = avg_uA / 1000.0f;
    return battery_mAh / avg_mA;
}

// Find period that gives target battery life
float calc_optimal_period_ms(float target_life_years,
                              float battery_mAh,
                              float active_mA,
                              float sleep_uA,
                              float active_ms) {
    float target_hours = target_life_years * 8760.0f;
    float target_mA    = battery_mAh / target_hours;
    float target_uA    = target_mA * 1000.0f;
    // target_uA = (active_ms/T) * active_mA*1000 + (1-active_ms/T) * sleep_uA
    // Solve for T:
    float active_uA = active_mA * 1000.0f;
    // target_uA = (active_ms/T)*(active_uA - sleep_uA) + sleep_uA
    // T = active_ms * (active_uA - sleep_uA) / (target_uA - sleep_uA)
    return active_ms * (active_uA - sleep_uA) / (target_uA - sleep_uA);
}

int main(void) {
    // Test 1: IoT sensor node
    PowerProfile iot = {
        .active_current_mA = 15.0f,
        .sleep_current_uA  = 5.0f,
        .active_time_ms    = 10.0f,
        .cycle_period_ms   = 60000.0f  // 60 seconds
    };
    float avg_uA = calc_average_current_uA(&iot);
    float life_h = calc_battery_life_hours(&iot, 1000.0f);
    float life_y = life_h / 8760.0f;
    printf("IoT Node:\n");
    printf("  Average: %.2f uA\n", avg_uA);
    printf("  Life: %.1f hours = %.1f years\n", life_h, life_y);
    assert(avg_uA > 5.0f && avg_uA < 20.0f);
    assert(life_y > 10.0f); // should be ~15 years
    printf("Test1 PASSED\n");

    // Test 2: Wearable
    PowerProfile wearable = {
        .active_current_mA = 50.0f,
        .sleep_current_uA  = 10.0f,
        .active_time_ms    = 100.0f,
        .cycle_period_ms   = 1000.0f  // 1 second
    };
    float w_avg = calc_average_current_uA(&wearable);
    float w_life = calc_battery_life_hours(&wearable, 200.0f) / 24.0f;
    printf("Wearable:\n");
    printf("  Average: %.1f uA\n", w_avg);
    printf("  Life: %.1f days\n", w_life);
    assert(w_avg > 1000.0f); // active 10% of time at 50mA
    printf("Test2 PASSED\n");

    // Test 3: Optimal period for 2-year target
    float opt_period_ms = calc_optimal_period_ms(
        2.0f,    // 2 years
        1000.0f, // 1000mAh battery
        15.0f,   // 15mA active
        5.0f,    // 5uA sleep
        10.0f    // 10ms active time
    );
    printf("Optimal period for 2yr life: %.0f ms = %.1f sec\n",
           opt_period_ms, opt_period_ms/1000.0f);
    assert(opt_period_ms > 1000.0f);
    printf("Test3 PASSED\n");

    printf("All battery calculator tests PASSED\n");
    return 0;
}

