// Lab 9: IoT Sensor JSON Library
#include <stdio.h>
#include <stdint.h>
#include <string.h>
#include <assert.h>
#include <math.h>

typedef struct {
    char     device_id[16];
    float    temperature;
    float    humidity;
    float    battery_v;
    int32_t  rssi;
    uint32_t timestamp;
} SensorData;

// Serialize SensorData to JSON
int sensor_to_json(const SensorData* s, char* buf, size_t maxlen) {
    return snprintf(buf, maxlen,
        "{\"id\":\"%s\",\"temp\":%.1f,\"hum\":%.1f,"
        "\"bat\":%.2f,\"rssi\":%d,\"ts\":%u}",
        s->device_id,
        s->temperature,
        s->humidity,
        s->battery_v,
        s->rssi,
        s->timestamp);
}

// Parse JSON to SensorData (simple parser)
int json_to_sensor(const char* json, SensorData* s) {
    memset(s, 0, sizeof(*s));
    // Simple sscanf-based parser
    int result = sscanf(json,
        "{\"id\":\"%15[^\"]\",\"temp\":%f,\"hum\":%f,"
        "\"bat\":%f,\"rssi\":%d,\"ts\":%u}",
        s->device_id,
        &s->temperature,
        &s->humidity,
        &s->battery_v,
        &s->rssi,
        &s->timestamp);
    return (result == 6) ? 1 : 0;
}

// Compare floats with tolerance
int float_eq(float a, float b, float tol) {
    return fabsf(a-b) < tol;
}

int main(void) {
    // Test 1: basic serialization
    SensorData sensor = {
        .device_id   = "sensor_001",
        .temperature = 24.5f,
        .humidity    = 58.2f,
        .battery_v   = 3.1f,
        .rssi        = -67,
        .timestamp   = 1698765432
    };

    char json_buf[256];
    int len = sensor_to_json(&sensor, json_buf, sizeof(json_buf));
    assert(len > 0 && len < 256);
    printf("JSON: %s\n", json_buf);
    assert(strstr(json_buf, "sensor_001") != NULL);
    assert(strstr(json_buf, "24.5") != NULL);
    printf("Test1 PASSED: serialization\n");

    // Test 2: parse JSON back
    SensorData parsed = {0};
    assert(json_to_sensor(json_buf, &parsed) == 1);
    assert(strcmp(parsed.device_id, "sensor_001") == 0);
    assert(float_eq(parsed.temperature, 24.5f, 0.1f));
    assert(float_eq(parsed.humidity, 58.2f, 0.1f));
    assert(parsed.rssi == -67);
    assert(parsed.timestamp == 1698765432);
    printf("Test2 PASSED: parsing\n");

    // Test 3: negative temperature
    sensor.temperature = -10.5f;
    sensor_to_json(&sensor, json_buf, sizeof(json_buf));
    assert(json_to_sensor(json_buf, &parsed) == 1);
    assert(float_eq(parsed.temperature, -10.5f, 0.1f));
    printf("Test3 PASSED: negative temp\n");

    printf("All IoT JSON tests PASSED\n");
    return 0;
}

