// Deadlock prevention pattern
// Always acquire mutexes in consistent order

// WRONG — deadlock risk:
void task_a(void* p) {
    xSemaphoreTake(mutex1, portMAX_DELAY);
    xSemaphoreTake(mutex2, portMAX_DELAY); // Task B has mutex2!
    // ... deadlock if Task B has mutex2 and wants mutex1
}
void task_b(void* p) {
    xSemaphoreTake(mutex2, portMAX_DELAY);
    xSemaphoreTake(mutex1, portMAX_DELAY); // Task A has mutex1!
}

// CORRECT — always acquire in same order:
void task_a_fixed(void* p) {
    xSemaphoreTake(mutex1, portMAX_DELAY);
    xSemaphoreTake(mutex2, portMAX_DELAY); // consistent order
}
void task_b_fixed(void* p) {
    xSemaphoreTake(mutex1, portMAX_DELAY); // same order!
    xSemaphoreTake(mutex2, portMAX_DELAY);
}

// Watchdog pattern with FreeRTOS
#define NUM_TASKS 3
volatile uint32_t task_heartbeat[NUM_TASKS] = {0};

void vWatchdogTask(void* p) {
    for (;;) {
        // Check all tasks kicked in last 1 second
        for (int i=0; i<NUM_TASKS; i++) {
            if (task_heartbeat[i] == 0) {
                // Task i hung! — log and reset
                HAL_NVIC_SystemReset();
            }
            task_heartbeat[i] = 0; // reset for next check
        }
        HAL_IWDG_Refresh(&hiwdg); // kick hardware watchdog
        vTaskDelay(pdMS_TO_TICKS(1000));
    }
}

// Priority Inversion Scenario
//
// Tasks:
// CommTask  (Priority 10) — must respond in <10ms
// CalcTask  (Priority 5)  — long computation
// LogTask   (Priority 1)  — writes to shared log buffer
//
// Shared resource: log_mutex protects log_buffer
//
// SEQUENCE (triggers priority inversion):
// t=0:   LogTask takes log_mutex (priority 1)
// t=1:   CommTask needs log_mutex → BLOCKS (waits for mutex)
//        Without priority inheritance:
//        LogTask still runs at priority 1
// t=2:   CalcTask (priority 5) preempts LogTask!
//        CalcTask runs for 200ms
//        LogTask (priority 1) can't run
//        CommTask (priority 10) can't run (waiting for mutex)
// t=202: CalcTask finishes → LogTask runs
// t=205: LogTask releases mutex → CommTask FINALLY runs
//        Latency: 205ms instead of <10ms!  DISASTER!
//
// FIX: FreeRTOS mutex with priority inheritance
// xSemaphoreCreateMutex()  (not xSemaphoreCreateBinary)
// When CommTask waits for log_mutex:
//   LogTask priority → temporarily raised to 10
//   CalcTask (priority 5) CANNOT preempt LogTask (now priority 10)
//   LogTask finishes quickly → CommTask runs at t=3ms ✓

