lab.starterCode:
// Lab 10: Priority Inversion Simulation
#include <stdio.h>
#include <assert.h>
#include <string.h>

// Simulated mutex
typedef struct {
    int owner_id;          // task ID of holder
    int owner_priority;    // current effective priority of holder
    int original_priority; // holder's real priority
    int locked;
} SimMutex;

void mutex_init(SimMutex* m) {
    m->locked = 0;
    m->owner_id = -1;
    m->owner_priority = -1;
    m->original_priority = -1;
}

// Try to take mutex. Returns cycles waited (0=immediate)
int mutex_take_with_inheritance(SimMutex* m, int task_id,
                                 int task_priority,
                                 int calc_priority,
                                 int calc_duration_cycles) {
    if (!m->locked) {
        // Mutex free — take immediately
        m->locked = 1;
        m->owner_id = task_id;
        m->owner_priority = task_priority;
        m->original_priority = m->owner_priority;
        return 0;
    }

    // Mutex taken — priority inheritance
    // Raise owner to our priority
    if (task_priority > m->owner_priority) {
        m->owner_priority = task_priority; // INHERITANCE!
        printf("  [Inheritance] Owner raised to priority %d\n",
               m->owner_priority);
    }

    // With inheritance: owner can't be preempted by calc_task
    // because owner_priority (now raised) >= calc_priority
    int preempted_cycles = 0;
    if (m->owner_priority < calc_priority) {
        // Without proper inheritance: calc preempts!
        preempted_cycles = calc_duration_cycles;
        printf("  [INVERSION] CalcTask preempts for %d cycles\n",
               calc_duration_cycles);
    } else {
        printf("  [OK] Inheritance prevents preemption\n");
    }

    // LogTask finishes work (simulated as 3 cycles)
    int log_cycles = 3;
    int total_wait = preempted_cycles + log_cycles;
    m->locked = 0;
    return total_wait;
}

int main(void) {
    SimMutex mutex;
    mutex_init(&mutex);

    // Simulate: LogTask (P1) holds mutex
    printf("=== Scenario: LogTask (P1) holds mutex ===\n");
    // LogTask takes mutex
    mutex.locked = 1;
    mutex.owner_id = 1;
    mutex.owner_priority = 1; // low priority
    mutex.original_priority = 1;

    // Test 1: WITHOUT priority inheritance
    printf("\n--- Without Inheritance ---\n");
    int wait_without = 0;
    // CalcTask (P5) > LogTask (P1) → preempts for 200 cycles
    if (mutex.owner_priority < 5) { // CalcTask priority
        wait_without += 200;
        printf("  CalcTask preempts LogTask for 200 cycles\n");
    }
    wait_without += 3; // LogTask finishes
    printf("  CommTask total wait: %d cycles\n", wait_without);
    assert(wait_without > 100); // priority inversion causes long wait
    printf("Test1 PASSED: inversion demonstrated (%d cycles)\n", wait_without);

    // Test 2: WITH priority inheritance
    printf("\n--- With Priority Inheritance ---\n");
    mutex_init(&mutex);
    mutex.locked = 1;
    mutex.owner_id = 1;
    mutex.owner_priority = 1;
    mutex.original_priority = 1;

    int wait_with = mutex_take_with_inheritance(
        &mutex,
        3,   // CommTask id
        10,  // CommTask priority
        5,   // CalcTask priority
        200  // CalcTask duration
    );
    printf("  CommTask total wait: %d cycles\n", wait_with);
    assert(wait_with < 10); // inheritance keeps wait short
    printf("Test2 PASSED: inheritance works (%d cycles)\n", wait_with);

    // Compare
    printf("\nSummary:\n");
    printf("  Without inheritance: %d cycles wait\n", wait_without);
    printf("  With inheritance:    %d cycles wait\n", wait_with);
    printf("  Improvement: %dx\n", wait_without / wait_with);
    assert(wait_without > wait_with * 10); // significant improvement

    printf("\nPriority inversion tests PASSED\n");
    return 0;
}

