// Lab 11: Complete UART Driver
#include <stdint.h>
#include <stdio.h>
#include <string.h>
#include <assert.h>

#define TX_BUF_SIZE 64
#define RX_BUF_SIZE 64

typedef struct {
    uint8_t  tx_buf[TX_BUF_SIZE];
