} UART;

void uart_init(UART* u) {
    memset(u, 0, sizeof(*u));
}

static uint8_t tx_full(const UART* u) {
    return ((u->tx_head + 1) % TX_BUF_SIZE) == u->tx_tail;
}
static uint8_t rx_full(const UART* u) {
    return ((u->rx_head + 1) % RX_BUF_SIZE) == u->rx_tail;
}
static uint8_t tx_empty(const UART* u) {
    return u->tx_head == u->tx_tail;
}
static uint8_t rx_empty(const UART* u) {
    return u->rx_head == u->rx_tail;
}

// Write to TX ring buffer (called by application)
int uart_write(UART* u, const uint8_t* data, uint16_t len) {
    int written = 0;
    for (uint16_t i = 0; i < len; i++) {
        if (tx_full(u)) break;
        u->tx_buf[u->tx_head] = data[i];
        u->tx_head = (u->tx_head + 1) % TX_BUF_SIZE;
        written++;
    }
    return written;
}

// Read from RX ring buffer (called by application)
int uart_read(UART* u, uint8_t* data, uint16_t maxlen) {
    int read = 0;
    while (read < maxlen && !rx_empty(u)) {
        data[read++] = u->rx_buf[u->rx_tail];
        u->rx_tail = (u->rx_tail + 1) % RX_BUF_SIZE;
    }
    return read;
}

// RX ISR: byte received from hardware
void uart_rx_isr(UART* u, uint8_t byte) {
    if (rx_full(u)) {
        u->overflow_count++;
        return; // drop byte
    }
    u->rx_buf[u->rx_head] = byte;
    u->rx_head = (u->rx_head + 1) % RX_BUF_SIZE;
    u->rx_count++;
}

// TX ISR: get next byte to transmit
// Returns 1 if byte available, 0 if TX buffer empty
int uart_tx_isr(UART* u, uint8_t* byte) {
    if (tx_empty(u)) return 0;
    *byte = u->tx_buf[u->tx_tail];
    u->tx_tail = (u->tx_tail + 1) % TX_BUF_SIZE;
    u->tx_count++;
    return 1;
}

uint16_t uart_available(const UART* u) {
    return (u->rx_head - u->rx_tail + RX_BUF_SIZE) % RX_BUF_SIZE;
}

int main(void) {
    UART uart;
    uart_init(&uart);

    // Test TX: write string, simulate ISR draining it
    const char* msg = "Hello World!";
    int written = uart_write(&uart, (uint8_t*)msg, strlen(msg));
    assert(written == (int)strlen(msg));
    printf("Written %d bytes to TX buffer\n", written);

    // Simulate TX ISR draining buffer byte by byte
    char tx_output[64];
    int tx_count = 0;
    uint8_t byte;
    while (uart_tx_isr(&uart, &byte)) {
        tx_output[tx_count++] = byte;
    }
    tx_output[tx_count] = '\0';
    assert(strcmp(tx_output, msg) == 0);
    printf("TX transmitted: '%s'\n", tx_output);
    printf("TX test PASSED\n");

    // Test RX: simulate ISR pushing bytes
    const char* incoming = "ACK OK";
    for (int i = 0; i < (int)strlen(incoming); i++)
        uart_rx_isr(&uart, incoming[i]);

    assert(uart_available(&uart) == (int)strlen(incoming));

    char rx_buf[32];
    int rx_count = uart_read(&uart, (uint8_t*)rx_buf, sizeof(rx_buf));
    rx_buf[rx_count] = '\0';
    assert(strcmp(rx_buf, incoming) == 0);
    printf("RX received: '%s'\n", rx_buf);
    printf("RX test PASSED\n");

    // Test overflow
    for (int i = 0; i < 70; i++) uart_rx_isr(&uart, 'X');
    assert(uart.overflow_count > 0);
    printf("Overflow detected: %u drops\n", uart.overflow_count);
    printf("Overflow test PASSED\n");

    printf("** UART Driver Interview PASSED **\n");
    return 0;
}

