lab.instructions:
# Lab 12: FINAL BOSS — Complete Embedded System

Implement a complete IoT temperature monitor system:

**Components:**
1. **Sensor driver**: read temperature (simulated ADC)
2. **Ring buffer**: interrupt-safe data storage  
3. **RTOS simulation**: cooperative multi-tasking
4. **MQTT serializer**: JSON payload builder
5. **OTA manager**: verify and apply firmware updates
6. **Watchdog**: detect hung tasks

```c
// System state machine
typedef enum {
    STATE_INIT, STATE_RUNNING,
    STATE_OTA, STATE_ERROR
} SystemState;

// Complete system
typedef struct {
    SystemState   state;
    float         temperature;
    uint32_t      sample_count;
    uint32_t      tx_count;
    uint32_t      error_count;
    uint8_t       watchdog_flags; // bit per task
    char          fw_version[8];
} SystemContext;
```

Implement and test all 6 components working together.

lab.starterCode:
// Lab 12: FINAL BOSS — Complete IoT Embedded System
#include <stdio.h>
#include <stdint.h>
#include <string.h>
#include <stdlib.h>
#include <assert.h>
#include <math.h>

// ── System State Machine ────────────────────────────────
typedef enum {
    STATE_INIT, STATE_RUNNING, STATE_OTA, STATE_ERROR
} SystemState;

typedef struct {
    SystemState state;
    float       temperature;
    uint32_t    sample_count;
    uint32_t    tx_count;
    uint32_t    error_count;
    uint8_t     watchdog_flags; // bit 0=sensor, bit 1=comm
    char        fw_version[8];
} SystemContext;

// ── Sensor Driver (simulated) ───────────────────────────
#define VREF 3.3f
#define ADC_MAX 4095

float sensor_read_temperature(uint32_t adc_raw) {
    // Simplified: map ADC 0-4095 to -40 to +125°C
    return -40.0f + ((float)adc_raw / ADC_MAX) * 165.0f;
}

// ── Ring Buffer ─────────────────────────────────────────
#define SAMPLE_BUF_SIZE 8

typedef struct {
    float    data[SAMPLE_BUF_SIZE];
    uint8_t  head, tail, count;
} SampleBuffer;

void   sbuf_init(SampleBuffer* b) { memset(b, 0, sizeof(*b)); }
void   sbuf_push(SampleBuffer* b, float v) {
    if (b->count >= SAMPLE_BUF_SIZE) return;
    b->data[b->head] = v;
    b->head = (b->head + 1) % SAMPLE_BUF_SIZE;
    b->count++;
}
float  sbuf_average(const SampleBuffer* b) {
    if (!b->count) return 0;
    float s = 0;
    for (int i=0; i<b->count; i++)
        s += b->data[(b->tail+i) % SAMPLE_BUF_SIZE];
    return s / b->count;
}

// ── MQTT JSON Serializer ────────────────────────────────
int build_mqtt_payload(const SystemContext* ctx, char* buf, int maxlen) {
    return snprintf(buf, maxlen,
        "{\"fw\":\"%s\",\"temp\":%.1f,"
        "\"samples\":%u,\"tx\":%u,\"err\":%u}",
        ctx->fw_version,
        ctx->temperature,
        ctx->sample_count,
        ctx->tx_count,
        ctx->error_count);
}

// ── OTA Manager ─────────────────────────────────────────
#define OTA_MAGIC 0xC0DE1234

typedef struct {
    uint32_t magic;
    uint32_t version;
    uint32_t size;
    uint32_t crc; // simplified
    uint8_t  data[64];
} OTAPacket;

uint32_t simple_checksum(const uint8_t* d, uint32_t len) {
    uint32_t sum = 0;
    for (uint32_t i=0; i<len; i++) sum += d[i];
    return sum;
}

int ota_verify(const OTAPacket* pkt) {
    if (pkt->magic != OTA_MAGIC) return 0;
    uint32_t crc = simple_checksum(pkt->data, pkt->size);
    return (crc == pkt->crc) ? 1 : 0;
}

int ota_apply(SystemContext* ctx, const OTAPacket* pkt) {
    if (!ota_verify(pkt)) return -1;
    // In real system: erase flash, write new firmware
    // Here: update version string
    snprintf(ctx->fw_version, sizeof(ctx->fw_version),
             "v%u", pkt->version);
    return 0;
}

// ── Watchdog ────────────────────────────────────────────
#define TASK_SENSOR_BIT 0x01
#define TASK_COMM_BIT   0x02
#define ALL_TASKS_MASK  0x03

void watchdog_kick(SystemContext* ctx, uint8_t task_bit) {
    ctx->watchdog_flags |= task_bit;
}

int watchdog_check(SystemContext* ctx) {
    if ((ctx->watchdog_flags & ALL_TASKS_MASK) == ALL_TASKS_MASK) {
        ctx->watchdog_flags = 0; // reset for next check
        return 1; // all tasks alive
    }
    return 0; // some task hung!
}

// ── Main System Test ────────────────────────────────────
int main(void) {
    SystemContext sys = {0};
    sys.state = STATE_INIT;
    strncpy(sys.fw_version, "v1.0.0", sizeof(sys.fw_version));

    SampleBuffer samples;
    sbuf_init(&samples);

    printf("=== FINAL BOSS: Complete IoT Embedded System ===\n");

    // ── INIT STATE ──
    sys.state = STATE_RUNNING;
    printf("System initialized: FW=%s\n", sys.fw_version);

    // ── SENSOR TASK ──
    printf("\n--- Sensor Task ---\n");
    uint32_t adc_readings[] = {2048, 2100, 2090, 2070, 2080};
    for (int i=0; i<5; i++) {
        float temp = sensor_read_temperature(adc_readings[i]);
        sbuf_push(&samples, temp);
        sys.sample_count++;
        watchdog_kick(&sys, TASK_SENSOR_BIT);
        printf("Sample %d: ADC=%u → %.1f°C\n", i+1, adc_readings[i], temp);
    }
    sys.temperature = sbuf_average(&samples);
    printf("Average temp: %.1f°C\n", sys.temperature);
    assert(sys.sample_count == 5);

    // ── COMM TASK ──
    printf("\n--- Comm Task (MQTT) ---\n");
    char mqtt_payload[256];
    int plen = build_mqtt_payload(&sys, mqtt_payload, sizeof(mqtt_payload));
    assert(plen > 0);
    printf("MQTT payload: %s\n", mqtt_payload);
    assert(strstr(mqtt_payload, sys.fw_version) != NULL);
    assert(strstr(mqtt_payload, "temp") != NULL);
    sys.tx_count++;
    watchdog_kick(&sys, TASK_COMM_BIT);

    // ── WATCHDOG CHECK ──
    printf("\n--- Watchdog Check ---\n");
    assert(watchdog_check(&sys) == 1);
    printf("All tasks alive: PASSED\n");

    // ── OTA UPDATE ──
    printf("\n--- OTA Update ---\n");
    OTAPacket ota = {
        .magic   = OTA_MAGIC,
        .version = 2,
        .size    = 10
    };
    for (int i=0; i<10; i++) ota.data[i] = i*2;
    ota.crc = simple_checksum(ota.data, ota.size);

    sys.state = STATE_OTA;
    assert(ota_apply(&sys, &ota) == 0);
    assert(strcmp(sys.fw_version, "v2") == 0);
    sys.state = STATE_RUNNING;
    printf("OTA applied: FW now = %s\n", sys.fw_version);

    // ── CORRUPT OTA ──
    OTAPacket bad_ota = ota;
    bad_ota.data[0] ^= 0xFF; // corrupt
    assert(ota_apply(&sys, &bad_ota) == -1);
    printf("Corrupt OTA rejected: PASSED\n");

    // ── FINAL REPORT ──
    printf("\n=== System Report ===\n");
    printf("FW Version:  %s\n", sys.fw_version);
    printf("Temperature: %.1f°C\n", sys.temperature);
    printf("Samples:     %u\n", sys.sample_count);
    printf("TX count:    %u\n", sys.tx_count);
    printf("Errors:      %u\n", sys.error_count);

    assert(sys.sample_count == 5);
    assert(sys.tx_count == 1);
    assert(sys.error_count == 0);

    printf("\n=== FINAL BOSS PASSED ===");
    printf(" All embedded system components working! ===\n");
    return 0;
}
